import React from "react";
import PlaceList from "../components/PlaceList";

const DUMMY_PLACES = [
  {
    id: 'p1',
    title: 'Gujarat state',
    description: 'One of the most famous sky scrapers in the world!',
    imageUrl: 'https://images.unsplash.com/photo-1490750967868-88aa4486c946.jpg',
    address: 'Devbhumi Dwarka district', // 👈 comma added
    location: {
      lat: 22.1320213,
      lng: 71.0503824,
    },
    creator: 'u1'
  },
  {
    id: 'p2',
    title: 'Gujarat state',
    description: 'One of the most famous sky scrapers in the world!',
    imageUrl: 'https://images.unsplash.com/photo-1490750967868-88aa4486c946.jpg',
    address: 'Devbhumi Dwarka district', // 👈 comma added
    location: {
      lat: 22.1320213,
      lng: 71.0503824,
    },
    creator: 'u2'
  }
];

const UserPlaces = () => {
  return <PlaceList items={DUMMY_PLACES} />;
};

export default UserPlaces;
